        <polyline points="0,102 18,82 36,68 54,62 72,59 90,57 108,62 126,65 144,74 162,85 180,99" fill="none" stroke="#94A3B8" stroke-width="1.6" stroke-dasharray="5 3" stroke-linecap="round"/>
